  1→import { GoogleGenAI, Type, Schema } from "@google/genai";
  2→
  3→// Helper to safely get env var
  4→const getApiKey = () => {
  5→  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
  6→    return process.env.API_KEY;
  7→  }
  8→  return null;
  9→};
 10→
 11→// Helper to simulate delay
 12→const delay = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));
 13→
 14→// ─── Interfaces ────────────────────────────────────────────────────────────────
 15→
 16→export interface AIEngineResponse {
 17→  engine: 'ChatGPT' | 'Claude' | 'Perplexity' | 'Gemini';
 18→  response: string;
 19→  mentionType: 'direct' | 'indirect' | 'comparison' | 'absent';
 20→  mentionScore: number;
 21→  sentiment: 'positive' | 'neutral' | 'negative';
 22→  citationPresent: boolean;
 23→  excerpt: string;
 24→}
 25→
 26→export interface CitationSimulationResult {
 27→  query: string;
 28→  brandName: string;
 29→  brandUrl: string;
 30→  overallScore: number;
 31→  engines: AIEngineResponse[];
 32→  improvements: string[];
 33→  competitorsMentioned: string[];
 34→}
 35→
 36→// ─── Industry competitor mapping ───────────────────────────────────────────────
 37→
 38→const INDUSTRY_COMPETITORS: Record<string, string[]> = {
 39→  saas: ['HubSpot', 'Salesforce', 'Monday.com', 'Notion', 'Airtable', 'Zendesk'],
 40→  ecommerce: ['Shopify', 'WooCommerce', 'BigCommerce', 'PrestaShop', 'Magento'],
 41→  marketing: ['SEMrush', 'Ahrefs', 'Moz', 'Mailchimp', 'HubSpot', 'Buffer'],
 42→  finance: ['Stripe', 'PayPal', 'Square', 'Wise', 'Revolut', 'Qonto'],
 43→  sante: ['Doctolib', 'Qare', 'Alan', 'Livi', 'Maiia'],
 44→  immobilier: ['SeLoger', 'LeBonCoin', 'Bien\'ici', 'MeilleursAgents', 'PAP'],
 45→  education: ['Coursera', 'Udemy', 'OpenClassrooms', 'Skillshare', 'LinkedIn Learning'],
 46→  restauration: ['TheFork', 'Uber Eats', 'Deliveroo', 'Zenchef', 'Lightspeed'],
 47→  juridique: ['LegalStart', 'Captain Contrat', 'Legalplace', 'Rocket Lawyer'],
 48→  default: ['HubSpot', 'Salesforce', 'Stripe', 'Notion', 'Ahrefs'],
 49→};
 50→
 51→const getCompetitors = (industry?: string): string[] => {
 52→  if (!industry) return INDUSTRY_COMPETITORS.default;
 53→  const key = industry.toLowerCase().trim();
 54→  return INDUSTRY_COMPETITORS[key] || INDUSTRY_COMPETITORS.default;
 55→};
 56→
 57→// ─── Fallback simulation (no API key) ──────────────────────────────────────────
 58→
 59→const fallbackSimulation = async (
 60→  query: string,
 61→  brandName: string,
 62→  brandUrl: string,
 63→  industry?: string
 64→): Promise<CitationSimulationResult> => {
 65→  // Simulate processing time
 66→  await delay(3000);
 67→
 68→  const competitors = getCompetitors(industry);
 69→  const hostname = new URL(brandUrl).hostname;
 70→  const industryLabel = industry || 'technology';
 71→
 72→  // Pick 3 competitors to mention across engines
 73→  const mentionedCompetitors = competitors.slice(0, 3);
 74→
 75→  // ── ChatGPT response: conversational tone ──
 76→  const chatgptResponse: AIEngineResponse = {
 77→    engine: 'ChatGPT',
 78→    response: `Great question! When it comes to ${query}, there are several strong options in the ${industryLabel} space. ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]} are widely recognized leaders that many businesses rely on. ${brandName} is also worth considering — they've been gaining traction with a focused approach to the problem. I'd recommend evaluating each based on your specific needs, budget, and team size to find the best fit.`,
 79→    mentionType: 'indirect',
 80→    mentionScore: 35,
 81→    sentiment: 'neutral',
 82→    citationPresent: false,
 83→    excerpt: `${brandName} is also worth considering — they've been gaining traction with a focused approach to the problem.`,
 84→  };
 85→
 86→  // ── Claude response: analytical and structured ──
 87→  const claudeResponse: AIEngineResponse = {
 88→    engine: 'Claude',
 89→    response: `Analyzing the ${industryLabel} landscape for "${query}", the market can be segmented into three tiers. Enterprise-grade solutions include ${mentionedCompetitors[0]} and ${mentionedCompetitors[1]}, which offer comprehensive feature sets but at higher price points. Mid-market alternatives such as ${mentionedCompetitors[2]} provide a balanced cost-to-value ratio. I don't have specific verified data about ${brandName} in my training set, so I'd recommend checking their website directly at ${hostname} for the most current information on their capabilities and positioning.`,
 90→    mentionType: 'indirect',
 91→    mentionScore: 20,
 92→    sentiment: 'neutral',
 93→    citationPresent: false,
 94→    excerpt: `I don't have specific verified data about ${brandName} in my training set, so I'd recommend checking their website directly at ${hostname}.`,
 95→  };
 96→
 97→  // ── Perplexity response: includes source citations ──
 98→  const perplexityResponse: AIEngineResponse = {
 99→    engine: 'Perplexity',
100→    response: `Based on recent analysis, the top solutions for ${query} in ${industryLabel} include ${mentionedCompetitors[0]} (ranked #1 by G2 in 2025) and ${mentionedCompetitors[1]} [1]. ${mentionedCompetitors[2]} is also frequently recommended for mid-size businesses [2]. ${brandName} does not currently appear in major comparison rankings for this category, though their website (${hostname}) indicates active development in this space [3].\n\nSources:\n[1] g2.com/categories/${industryLabel}\n[2] capterra.com/reviews\n[3] ${hostname}`,
101→    mentionType: 'absent',
102→    mentionScore: 10,
103→    sentiment: 'neutral',
104→    citationPresent: true,
105→    excerpt: `${brandName} does not currently appear in major comparison rankings for this category.`,
106→  };
107→
108→  // ── Gemini response: factual and data-driven ──
109→  const geminiResponse: AIEngineResponse = {
110→    engine: 'Gemini',
111→    response: `For "${query}", the ${industryLabel} market in 2025 is valued at approximately $XX billion globally. The primary vendors are ${mentionedCompetitors[0]} (market share ~25%), ${mentionedCompetitors[1]} (~18%), and ${mentionedCompetitors[2]} (~12%). ${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited at this time. Key selection criteria include pricing, integration capabilities, and customer support quality.`,
112→    mentionType: 'direct',
113→    mentionScore: 40,
114→    sentiment: 'neutral',
115→    citationPresent: false,
116→    excerpt: `${brandName} is a newer entrant in this segment. According to available data, they offer services through ${hostname}, though detailed market share figures and independent reviews are limited.`,
117→  };
118→
119→  const engines: AIEngineResponse[] = [
120→    chatgptResponse,
121→    claudeResponse,
122→    perplexityResponse,
123→    geminiResponse,
124→  ];
125→
126→  // Calculate overall score as the average of all engine mention scores
127→  const overallScore = Math.round(
128→    engines.reduce((sum, e) => sum + e.mentionScore, 0) / engines.length
129→  );
130→
131→  // Improvement suggestions
132→  const improvements: string[] = [
133→    `Create a comprehensive "About" page on ${hostname} with structured data (Schema.org Organization) so AI models can extract authoritative entity information.`,
134→    `Publish original research, benchmarks, or case studies related to "${query}" to build topical authority that AI engines reference.`,
135→    `Ensure ${brandName} is listed on major comparison platforms (G2, Capterra, TrustPilot) with verified reviews — Perplexity and ChatGPT heavily rely on these sources.`,
136→    `Add FAQ sections with "Answer-First" formatting on key landing pages to increase the probability of direct AI citations.`,
137→    `Build backlinks from authoritative industry publications and directories so AI models associate ${brandName} with the "${industryLabel}" topic cluster.`,
138→    `Implement llms.txt and llms-full.txt files at ${hostname}/llms.txt to provide AI crawlers with a structured, canonical source of truth about your brand.`,
139→  ];
140→
141→  return {
142→    query,
143→    brandName,
144→    brandUrl,
145→    overallScore,
146→    engines,
147→    improvements,
148→    competitorsMentioned: mentionedCompetitors,
149→  };
150→};
151→
152→// ─── Gemini API call ───────────────────────────────────────────────────────────
153→
154→const simulateWithGemini = async (
155→  query: string,
156→  brandName: string,
157→  brandUrl: string,
158→  industry?: string
159→): Promise<CitationSimulationResult> => {
160→  const apiKey = getApiKey();
161→  if (!apiKey) {
162→    throw new Error("No API key available");
163→  }
164→
165→  const ai = new GoogleGenAI({ apiKey });
166→
167→  const engineResponseSchema: Schema = {
168→    type: Type.OBJECT,
169→    properties: {
170→      engine: {
171→        type: Type.STRING,
172→        enum: ['ChatGPT', 'Claude', 'Perplexity', 'Gemini'],
173→        description: "The AI engine being simulated",
174→      },
175→      response: {
176→        type: Type.STRING,
177→        description: "The simulated AI response text (3-5 sentences). ChatGPT: conversational. Claude: analytical and structured. Perplexity: include source citation format [1][2]. Gemini: factual and data-driven.",
178→      },
179→      mentionType: {
180→        type: Type.STRING,
181→        enum: ['direct', 'indirect', 'comparison', 'absent'],
182→        description: "How the brand is mentioned: direct (by name in context), indirect (alluded to), comparison (mentioned alongside competitors), absent (not mentioned)",
183→      },
184→      mentionScore: {
185→        type: Type.NUMBER,
186→        description: "0-100 score of how prominently the brand is featured in the response",
187→      },
188→      sentiment: {
189→        type: Type.STRING,
190→        enum: ['positive', 'neutral', 'negative'],
191→        description: "Sentiment of the mention toward the brand",
192→      },
193→      citationPresent: {
194→        type: Type.BOOLEAN,
195→        description: "Whether the engine includes a source citation or link for the brand",
196→      },
197→      excerpt: {
198→        type: Type.STRING,
199→        description: "The specific part of the response that mentions the brand, or empty string if absent",
200→      },
201→    },
202→    required: ['engine', 'response', 'mentionType', 'mentionScore', 'sentiment', 'citationPresent', 'excerpt'],
203→  };
204→
205→  const resultSchema: Schema = {
206→    type: Type.OBJECT,
207→    properties: {
208→      overallScore: {
209→        type: Type.NUMBER,
210→        description: "0-100 average visibility score across all engines",
211→      },
212→      engines: {
213→        type: Type.ARRAY,
214→        items: engineResponseSchema,
215→        description: "Simulated responses from 4 AI engines: ChatGPT, Claude, Perplexity, Gemini",
216→      },
217→      improvements: {
218→        type: Type.ARRAY,
219→        items: { type: Type.STRING },
220→        description: "4-6 actionable improvement suggestions to increase AI citation visibility",
221→      },
222→      competitorsMentioned: {
223→        type: Type.ARRAY,
224→        items: { type: Type.STRING },
225→        description: "Names of competitors mentioned across the simulated responses",
226→      },
227→    },
228→    required: ['overallScore', 'engines', 'improvements', 'competitorsMentioned'],
229→  };
230→
231→  const industryContext = industry ? `The brand operates in the "${industry}" industry.` : '';
232→
233→  const prompt = `
234→    CONTEXT:
235→    You are an expert in AI visibility and Answer Engine Optimization (AEO).
236→    A user wants to understand how different AI engines would respond to a query about their brand.
237→
238→    INPUTS:
239→    - User query: "${query}"
240→    - Brand name: "${brandName}"
241→    - Brand URL: ${brandUrl}
242→    ${industryContext}
243→
244→    MISSION:
245→    Simulate how each of the 4 major AI engines (ChatGPT, Claude, Perplexity, Gemini) would realistically respond to the query "${query}".
246→
247→    RULES FOR EACH ENGINE:
248→    1. **ChatGPT**: Conversational, friendly tone. May mention the brand if it has strong web presence. Tends to recommend well-known solutions first.
249→    2. **Claude**: Analytical, structured analysis. Cautious about unverified claims. Will note if it lacks training data on the brand.
250→    3. **Perplexity**: Always includes numbered source citations [1][2][3]. Relies heavily on indexed web sources, comparison sites, and reviews.
251→    4. **Gemini**: Factual, data-driven. Focuses on market data, statistics, and objective comparisons.
252→
253→    IMPORTANT:
254→    - Be realistic: if the brand is not well-known, some engines should NOT mention it or mention it minimally.
255→    - Each response should be 3-5 sentences of natural AI-style text.
256→    - Vary the mentionType across engines (not all should be the same).
257→    - Include real competitor names relevant to the industry.
258→    - Provide 4-6 specific, actionable improvement suggestions.
259→    - The overallScore should reflect the average mentionScore across engines.
260→
261→    Respond strictly in the JSON schema provided.
262→  `;
263→
264→  const response = await ai.models.generateContent({
265→    model: 'gemini-2.5-flash',
266→    contents: prompt,
267→    config: {
268→      responseMimeType: 'application/json',
269→      responseSchema: resultSchema,
270→      temperature: 0.4,
271→    },
272→  });
273→
274→  let output = response.text;
275→  if (!output) {
276→    throw new Error("Empty response from AI");
277→  }
278→
279→  // Clean up potentially leaked markdown fences despite JSON mode
280→  output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
281→
282→  const jsonResponse = JSON.parse(output);
283→
284→  return {
285→    query,
286→    brandName,
287→    brandUrl,
288→    overallScore: jsonResponse.overallScore,
289→    engines: jsonResponse.engines,
290→    improvements: jsonResponse.improvements,
291→    competitorsMentioned: jsonResponse.competitorsMentioned,
292→  };
293→};
294→
295→// ─── Main exported function ────────────────────────────────────────────────────
296→
297→export const simulateCitation = async (
298→  query: string,
299→  brandName: string,
300→  brandUrl: string,
301→  industry?: string
302→): Promise<CitationSimulationResult> => {
303→  const apiKey = getApiKey();
304→
305→  if (!apiKey) {
306→    console.warn("API_KEY not found or process.env unavailable, using fallback simulation.");
307→    return fallbackSimulation(query, brandName, brandUrl, industry);
308→  }
309→
310→  try {
311→    return await simulateWithGemini(query, brandName, brandUrl, industry);
312→  } catch (error) {
313→    console.error("AI Citation Simulation failed:", error);
314→    return fallbackSimulation(query, brandName, brandUrl, industry);
315→  }
316→};
