  1→import React, { createContext, useContext, useState, useCallback, useMemo, useEffect } from 'react';
  2→import { Locale, TranslationDictionary, SUPPORTED_LOCALES } from './types';
  3→import fr from './locales/fr';
  4→import en from './locales/en';
  5→import es from './locales/es';
  6→
  7→// ================================================================
  8→// DICTIONNAIRES
  9→// ================================================================
 10→
 11→const dictionaries: Record<Locale, TranslationDictionary> = { fr, en, es };
 12→
 13→// ================================================================
 14→// CONTEXT
 15→// ================================================================
 16→
 17→interface I18nContextValue {
 18→  locale: Locale;
 19→  setLocale: (locale: Locale) => void;
 20→  t: TranslationDictionary;
 21→  /** Format a template string like "Hello {name}" with values */
 22→  tf: (template: string, values: Record<string, string | number>) => string;
 23→  /** Get the AI prompt language instruction for the current locale */
 24→  promptLang: string;
 25→}
 26→
 27→const I18nContext = createContext<I18nContextValue | null>(null);
 28→
 29→// ================================================================
 30→// STORAGE KEY
 31→// ================================================================
 32→
 33→const LOCALE_STORAGE_KEY = 'citedby_locale';
 34→
 35→const getInitialLocale = (): Locale => {
 36→  // 1. Check localStorage
 37→  if (typeof window !== 'undefined') {
 38→    const stored = localStorage.getItem(LOCALE_STORAGE_KEY);
 39→    if (stored && ['fr', 'en', 'es'].includes(stored)) {
 40→      return stored as Locale;
 41→    }
 42→    // 2. Check browser language
 43→    const browserLang = navigator.language.slice(0, 2);
 44→    if (['fr', 'en', 'es'].includes(browserLang)) {
 45→      return browserLang as Locale;
 46→    }
 47→  }
 48→  // 3. Default to French
 49→  return 'fr';
 50→};
 51→
 52→// ================================================================
 53→// PROVIDER
 54→// ================================================================
 55→
 56→interface I18nProviderProps {
 57→  children: React.ReactNode;
 58→  defaultLocale?: Locale;
 59→}
 60→
 61→export const I18nProvider: React.FC<I18nProviderProps> = ({ children, defaultLocale }) => {
 62→  const [locale, setLocaleState] = useState<Locale>(defaultLocale || getInitialLocale());
 63→
 64→  const setLocale = useCallback((newLocale: Locale) => {
 65→    setLocaleState(newLocale);
 66→    if (typeof window !== 'undefined') {
 67→      localStorage.setItem(LOCALE_STORAGE_KEY, newLocale);
 68→    }
 69→  }, []);
 70→
 71→  // Persist on change
 72→  useEffect(() => {
 73→    if (typeof window !== 'undefined') {
 74→      localStorage.setItem(LOCALE_STORAGE_KEY, locale);
 75→    }
 76→  }, [locale]);
 77→
 78→  const t = useMemo(() => dictionaries[locale], [locale]);
 79→
 80→  const tf = useCallback((template: string, values: Record<string, string | number>) => {
 81→    let result = template;
 82→    for (const [key, value] of Object.entries(values)) {
 83→      result = result.replace(new RegExp(`\\{${key}\\}`, 'g'), String(value));
 84→    }
 85→    return result;
 86→  }, []);
 87→
 88→  const promptLang = useMemo(() => t.prompts.outputLanguageInstruction, [t]);
 89→
 90→  const value = useMemo<I18nContextValue>(() => ({
 91→    locale,
 92→    setLocale,
 93→    t,
 94→    tf,
 95→    promptLang,
 96→  }), [locale, setLocale, t, tf, promptLang]);
 97→
 98→  return (
 99→    <I18nContext.Provider value={value}>
100→      {children}
101→    </I18nContext.Provider>
102→  );
103→};
104→
105→// ================================================================
106→// HOOKS
107→// ================================================================
108→
109→export const useTranslation = (): I18nContextValue => {
110→  const context = useContext(I18nContext);
111→  if (!context) {
112→    throw new Error('useTranslation must be used within an I18nProvider');
113→  }
114→  return context;
115→};
116→
117→/** Shortcut hook to get just the locale and setter */
118→export const useLocale = (): { locale: Locale; setLocale: (l: Locale) => void } => {
119→  const { locale, setLocale } = useTranslation();
120→  return { locale, setLocale };
121→};
