 27→// Heuristics to detect platform based on URL pattern (Simulation)
 28→const detectPlatform = (url: string): PlatformConfig => {
 29→  const lowerUrl = url.toLowerCase();
 30→  
 31→  if (lowerUrl.includes('shopify') || lowerUrl.includes('store') || lowerUrl.includes('shop')) {
 32→    return {
 33→      name: 'Shopify / E-commerce',
 34→      disallow: ['/cart', '/orders', '/checkouts', '/account', '/collections/*+*', '/blogs/*+*', '/*design_theme_id'],
 35→      sitemaps: ['/sitemap.xml', '/sitemap_products_1.xml']
 36→    };
 37→  }
 38→  
 39→  if (lowerUrl.includes('wordpress') || lowerUrl.includes('blog') || lowerUrl.includes('wp-')) {
 40→    return {
 41→      name: 'WordPress',
 42→      disallow: ['/wp-admin/', '/wp-includes/', '/wp-content/plugins/', '/xmlrpc.php', '/readme.html', '/?s='],
 43→      sitemaps: ['/sitemap_index.xml', '/post-sitemap.xml']
 44→    };
 45→  }
 46→
 47→  if (lowerUrl.includes('app.') || lowerUrl.includes('dashboard') || lowerUrl.includes('portal')) {
 48→    return {
 49→      name: 'SaaS / Web App',
 50→      disallow: ['/api/', '/dashboard/', '/settings/', '/user/', '/private/', '/auth/'],
 51→      sitemaps: ['/sitemap.xml']
 52→    };
 53→  }
 54→
 55→  // Default / Generic
 56→  return {
 57→    name: 'Site Général',
 58→    disallow: ['/admin/', '/login/', '/tmp/', '/private/', '/search'],
 59→    sitemaps: ['/sitemap.xml']
 60→  };
 61→};
