127→export const parseCurrentRobotsTxt = (url: string): string => {
128→  // We simulate what a "standard" unoptimized file looks like based on platform
129→  const platform = detectPlatform(url);
130→  
131→  let content = `User-agent: *\n`;
132→  
133→  if (platform.name === 'WordPress') {
134→    content += `Disallow: /wp-admin/\nAllow: /wp-admin/admin-ajax.php\n`;
135→  } else if (platform.name.includes('Shopify')) {
136→    content += `Disallow: /cart\nDisallow: /orders\n`;
137→  } else {
138→    content += `Disallow: /admin/\nDisallow: /tmp/\n`;
139→  }
140→
141→  content += `\nSitemap: ${url}/sitemap.xml`;
142→  
143→  return content;
144→};
