// 1. API KEY RETRIEVAL (Safe for browser/server)
const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// 2. FALLBACK SIMULATION (if no API key or request fails)
const fallbackSimulation = async (...): Promise<Result> => {
  await delay(2000-3000); // Realistic latency
  return { /* hardcoded response */ };
};

// 3. MAIN FUNCTION WITH API CALL + ERROR HANDLING
export const functionName = async (...): Promise<Result> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.warn("API_KEY not found, using fallback simulation.");
    return fallbackSimulation(...);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    // Define strict JSON schema for response
    const schema: Schema = {
      type: Type.OBJECT,
      properties: {
        field1: { type: Type.STRING, description: "..." },
        field2: { type: Type.ARRAY, items: { type: Type.STRING } },
        // ...
      },
      required: ["field1", "field2"],
    };

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',  // or 'gemini-2.5-pro' for long-form
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: 'application/json',
        responseSchema: schema,
        temperature: 0.3-0.7,  // Varies by task
      }
    });

    let output = response.text;
    // Clean up markdown fences if leaked
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const parsed = JSON.parse(output);

    return {
      ...parsed,
      // Additional processing
    };
  } catch (error) {
    console.error("AI call failed:", error);
    return fallbackSimulation(...);  // Graceful fallback
  }
};
```

